import anthropic

client = anthropic.Anthropic()
print("Starting analysis...")
thinking_shown = False

with client.messages.stream(
    model='claude-opus-4-6',
    max_tokens=16000,
    thinking={'type': 'enabled', 'budget_tokens': 8000},
    messages=[{'role': 'user', 'content': 'Explain the CAP theorem with examples.'}]
) as stream:
    for event in stream:
        if hasattr(event, 'type'):
            if event.type == 'content_block_start':
                if hasattr(event, 'content_block'):
                    if event.content_block.type == 'thinking':
                        print("\n[Thinking...] ", end='', flush=True)
                        thinking_shown = True
                    elif event.content_block.type == 'text':
                        if thinking_shown:
                            print("\n\n[Response]\n", flush=True)
            elif event.type == 'content_block_delta':
                if hasattr(event, 'delta'):
                    if hasattr(event.delta, 'thinking'):
                        print('.', end='', flush=True)  # progress dots
                    elif hasattr(event.delta, 'text'):
                        print(event.delta.text, end='', flush=True)
print("\n\n[Done]")

class BudgetAwareAgent:
    def __init__(self, total_thinking_budget: int = 60_000):
        self.total_budget = total_thinking_budget
        self.used_tokens = 0
        self.client = anthropic.Anthropic()

    def remaining_budget(self) -> int:
        return max(1024, self.total_budget - self.used_tokens)

    def budget_for_turn(self, turn_complexity: str = 'medium') -> int:
        """Allocate a fraction of remaining budget based on estimated complexity."""
        remaining = self.remaining_budget()
        fractions = {
            'low':      0.05,
            'medium':   0.15,
            'high':     0.30,
            'critical': 0.50
        }
        fraction = fractions.get(turn_complexity, 0.15)
        allocation = int(remaining * fraction)
        return max(1024, min(allocation, 32000))

    def invoke(self, message: str, complexity: str = 'medium') -> str:
        budget = self.budget_for_turn(complexity)
        print(f"Turn budget: {budget:,} tokens (remaining: {self.remaining_budget():,})")

        response = self.client.messages.create(
            model='claude-opus-4-6',
            max_tokens=budget + 4000,
            thinking={'type': 'enabled', 'budget_tokens': budget},
            messages=[{'role': 'user', 'content': message}]
        )

        # Conservative: count full budget allocation as used
        # (prevents runaway spending on later turns)
        self.used_tokens += budget

        return ''.join(b.text for b in response.content if b.type == 'text')

agent = BudgetAwareAgent(total_thinking_budget=50_000)
response1 = agent.invoke('Analyze this complex bug', complexity='high')
response2 = agent.invoke('What file should I look at next?', complexity='medium')
response3 = agent.invoke('Apply the fix', complexity='low')
